(function($,window,document){'use strict';function WSE_Swatches($form){this.$form=$form;this._origGallery=null;this._init();}
WSE_Swatches.prototype={_init:function(){this._bindSwatchClick();this._bindKeyboardNav();this._bindResetData();this._bindVariationEvents();this._updateAllResetLinks();this._syncInitialSelections();},_bindSwatchClick:function(){var self=this;this.$form.on('click.wse','.wse-swatch',function(e){e.preventDefault();var $swatch=$(this);var attribute=$swatch.data('attribute');var value=$swatch.data('value');if($swatch.hasClass('disabled')){return;}
if($swatch.hasClass('selected')){self._deselectAttribute(attribute);return;}
self._selectSwatch($swatch,attribute,value);});},_selectSwatch:function($swatch,attribute,value){var self=this;var $wrap=this.$form.find('.wse-swatch-wrap[data-attribute="'+attribute+'"]');var $select=this.$form.find('select[name="attribute_'+attribute+'"]');var $siblings=$wrap.find('.wse-swatch');$siblings.removeClass('selected').attr('aria-checked','false').attr('tabindex','-1');$swatch.addClass('selected').attr('aria-checked','true').attr('tabindex','0');$select.val(value).trigger('change');$wrap.find('.wse-reset-link').show();var $selectedVal=self.$form.find('.wse-attr-selected-val[data-attribute="'+attribute+'"]');if($selectedVal.length){$selectedVal.text($swatch.attr('title')||value);}
$(document.body).trigger('wse:swatchSelected',[{attribute:attribute,value:value,$swatch:$swatch,$form:self.$form,}]);},_syncInitialSelections:function(){var self=this;this.$form.find('.wse-swatch-wrap[data-attribute]').each(function(){var $wrap=$(this);var attribute=$wrap.data('attribute');var $select=self.$form.find('select[name="attribute_'+attribute+'"]');var value=$select.val();if(!value){return;}
var $swatch=$wrap.find('.wse-swatch[data-value="'+value+'"]');$(document.body).trigger('wse:swatchSelected',[{attribute:attribute,value:value,$swatch:$swatch,$form:self.$form,}]);});},_deselectAttribute:function(attribute){var self=this;var $wrap=this.$form.find('.wse-swatch-wrap[data-attribute="'+attribute+'"]');var $select=this.$form.find('select[name="attribute_'+attribute+'"]');$wrap.find('.wse-swatch').removeClass('selected').attr('aria-checked','false').attr('tabindex','-1');$wrap.find('.wse-swatch:not(.disabled)').first().attr('tabindex','0');$select.val('').trigger('change');$wrap.find('.wse-reset-link').hide();self.$form.find('.wse-attr-selected-val[data-attribute="'+attribute+'"]').text('');$(document.body).trigger('wse:swatchDeselected',[{attribute:attribute,$form:self.$form,}]);},_bindKeyboardNav:function(){var self=this;this.$form.on('keydown.wse','.wse-swatch',function(e){var $current=$(this);var attribute=$current.data('attribute');var $wrap=self.$form.find('.wse-swatch-wrap[data-attribute="'+attribute+'"]');var $available=$wrap.find('.wse-swatch:not(.disabled)');var idx=$available.index($current);var last=$available.length-1;switch(e.key){case'Enter':case' ':e.preventDefault();$current.trigger('click.wse');break;case'ArrowRight':case'ArrowDown':e.preventDefault();$available.attr('tabindex','-1');$available.eq(idx<last?idx+1:0).attr('tabindex','0').focus();break;case'ArrowLeft':case'ArrowUp':e.preventDefault();$available.attr('tabindex','-1');$available.eq(idx>0?idx-1:last).attr('tabindex','0').focus();break;}});},_bindResetData:function(){var self=this;this.$form.on('reset_data.wse',function(){self._onResetData();});this.$form.on('click.wse','.wse-reset-link',function(e){e.preventDefault();self.$form.find('.variations select').val('').trigger('change');self._onResetData();});},_onResetData:function(){this.$form.find('.wse-swatch').removeClass('selected').attr('aria-checked','false').attr('tabindex','-1');var self=this;this.$form.find('.wse-swatch-wrap').each(function(){$(this).find('.wse-swatch:not(.disabled)').first().attr('tabindex','0');});this.$form.find('.wse-reset-link').hide();this.$form.find('.wse-attr-selected-val').text('');this._restoreGallery();$(document.body).trigger('wse:swatchReset',[{$form:self.$form}]);},_bindVariationEvents:function(){var self=this;this.$form.on('found_variation.wse',function(e,variation){self._onFoundVariation(variation);});this.$form.on('hide_variation.wse',function(){self._restoreGallery();});},_onFoundVariation:function(variation){if(!variation.image||!variation.image.src||variation.image.src.length===0){return;}
var $img=this._getGalleryImage();if(!$img.length){return;}
if(!this._origGallery){var $link=$img.closest('a');this._origGallery={src:$img.attr('src')||'',srcset:$img.attr('srcset')||'',href:$link.attr('href')||'',};}
$img.attr('src',variation.image.src);$img.attr('srcset',variation.image.srcset||'');var $anchor=$img.closest('a');if($anchor.length){$anchor.attr('href',variation.image.full_src||variation.image.src);}
$(document.body).trigger('wc_update_variation_image',[variation]);},_restoreGallery:function(){if(!this._origGallery){return;}
var $img=this._getGalleryImage();var $anchor=$img.closest('a');$img.attr('src',this._origGallery.src);$img.attr('srcset',this._origGallery.srcset);if($anchor.length&&this._origGallery.href){$anchor.attr('href',this._origGallery.href);}},_getGalleryImage:function(){return $('.woocommerce-product-gallery__image:first-child img');},_updateAllResetLinks:function(){this.$form.find('.wse-swatch-wrap').each(function(){var $wrap=$(this);var hasSelected=$wrap.find('.wse-swatch.selected').length>0;$wrap.find('.wse-reset-link').toggle(hasSelected);});},};function initAll(){$('form.variations_form').each(function(){var $form=$(this);if($form.data('wse-swatches')){return;}
$form.data('wse-swatches',new WSE_Swatches($form));});}
$(document).ready(initAll);$(document.body).on('wc_variation_form woocommerce_variation_has_changed '+'post-load elementor/popup/show wse:reinit',initAll);})(jQuery,window,document);